$(document).ready(function(){AOS.init({disable:"mobile"}),$(".scrollbar").mCustomScrollbar({mouseWheel:{preventDefault:!1}}),$.fn.randomize=function(e){return(e?$(this).find(e):$(this).children()).parent().each(function(){$(this).children(e).sort(function(n,t){if($(t).index()!==$(this).children(e).length-1)return Math.round(Math.random())-.5}.bind(this)).detach().appendTo(this)}),this},$(".quote-carousel").randomize().slick({autoplay:!0,autoplaySpeed:4e3,arrows:!1,fade:!0,pauseOnFocus:!1,pauseOnHover:!1})});